/**
 * Mock data for Growth · Email Flows.
 *
 * Three states drive the list and detail panel:
 *   - active  → performance vs benchmark (KPI rows)
 *   - paused  → leak bar showing what it earned when on
 *   - missing → opportunity grid (data source, benchmark, effort, time)
 */

export type FlowState = "active" | "paused" | "missing";
export type FlowTone = "green" | "amber" | "red" | "compass";
export type FlowIconKey = "cart" | "mail" | "eye" | "loop" | "star" | "hex";

export interface FlowKpi {
  /** Label e.g. "Conv rate" */
  label: string;
  /** Display value, e.g. "12.4%" */
  value: string;
  /** Ratio vs benchmark (0..2 — 1.0 is on benchmark). */
  ratio: number;
  /** 1 = above avg, 0 = below avg */
  good: 0 | 1;
  /** Delta description, e.g. "above avg" or "40% below avg" */
  delta: string;
}

export interface FlowRow {
  id: string;
  name: string;
  iconKey: FlowIconKey;
  state: FlowState;
  v: FlowTone;
  /** Bar width fuel — value vs MAX_FLOW_VALUE. */
  value: number;
  /** Number of emails in the flow (active/paused only). */
  emails?: number;
  /** Money/opportunity display string. */
  money: string;
  /** "$44K" — what the platform claimed (active only). */
  claimed?: string;
  /** "↓ 38% air" or "✓ 14% honest". */
  air?: string;
  airGood?: boolean;
  /** Period-over-period trend (active only). */
  trend?: string;
  /** Sub-line in the list row, e.g. "1 email · paused 14 days". */
  sub?: string;
  /** What it was earning before being paused (paused only). */
  was?: number;
  /** HIGH/MEDIUM priority label for missing flows. */
  priority?: "HIGH" | "MEDIUM";
  /** Range string for the unbuilt opportunity, e.g. "$42–63K". */
  est?: string;
  /** Marks the sunset/deliverability flow. */
  deliverability?: boolean;
  /** "9,960 product viewers …" — the data point that surfaces the opportunity. */
  data?: string;
  bench?: string;
  effort?: string;
  /** "3–5 days to start · full effect in 30" */
  time?: string;
  /** The Magellan read — a short paragraph in the detail. */
  read: string;
  /** Closing italic argument line. */
  line: string;
  /** KPI list (active only). */
  kpis?: FlowKpi[];
}

